const MAXB = 2500;
const NL = String.fromCharCode(10);
const FENCE = String.fromCharCode(96) + String.fromCharCode(96) + String.fromCharCode(96);
const enc = new TextEncoder();
function blen(s){ return enc.encode(s).length; }
const it = $input.first().json || {};
const channel = String(it.channel || '');
const text = (it.text == null) ? '' : String(it.text);
const threadTs = it.threadTs ? String(it.threadTs) : '';
const updateTs = it.updateTs ? String(it.updateTs) : '';
const threadEff = threadTs || updateTs;
function hardSplit(line, maxb){ var out=[]; var cur=''; var arr=Array.from(line); for(var i=0;i<arr.length;i++){ var ch=arr[i]; if(blen(cur+ch)>maxb){ if(cur)out.push(cur); cur=ch; } else { cur+=ch; } } if(cur)out.push(cur); return out.length?out:['']; }
function splitText(s, maxb){ if(!s) return ['']; var lines=s.split(NL); var chunks=[]; var cur=''; for(var i=0;i<lines.length;i++){ var line=lines[i]; var pieces=(blen(line)>maxb)?hardSplit(line,maxb):[line]; for(var k=0;k<pieces.length;k++){ var piece=pieces[k]; var cand=cur?(cur+NL+piece):piece; if(blen(cand)>maxb){ if(cur)chunks.push(cur); cur=piece; } else { cur=cand; } } } if(cur)chunks.push(cur); return chunks.length?chunks:['']; }
var chunks = splitText(text, MAXB);
var fixed=[]; var carry=null;
for(var i=0;i<chunks.length;i++){ var c=chunks[i]; if(carry!==null){ c=FENCE+carry+NL+c; } var fc=c.split(FENCE).length-1; carry=null; if(fc%2===1){ var lo=c.lastIndexOf(FENCE); var after=c.slice(lo+3); carry=(after.split(NL)[0]||'').trim(); c=c+NL+FENCE; } fixed.push(c); }
chunks=fixed;
var total=chunks.length; var out=[];
for(var i=0;i<chunks.length;i++){ var isFirst=(i===0); var useUpdate=isFirst && !!updateTs; var label=(total>1)?(NL+NL+'_('+(i+1)+'/'+total+')_'):''; var body={channel:channel, text:chunks[i]+label}; if(useUpdate){ body.ts=updateTs; } else if(threadEff){ body.thread_ts=threadEff; } out.push({json:{apiUrl: useUpdate?'https://slack.com/api/chat.update':'https://slack.com/api/chat.postMessage', body:body, idx:i, total:total}}); }
return out;

